#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n, d;
        scanf("%d %d", &n, &d);
        int a[n];
        for (int i = 0; i < n; i++) {
            scanf("%d", &a[i]);
        }
        int prefix[n + 1] = {0};
        for (int i = 0; i < n; i++) {
            prefix[i + 1] = prefix[i] + a[i];
        }
        int min_length = n + 1;
        for (int i = 0; i < n; i++) {
            for (int j = i; j < n; j++) {
                int sum = prefix[j + 1] - prefix[i];
                if (sum >= d) {
                    min_length = (min_length < (j - i + 1)) ? min_length : (j - i + 1);
                }
            }
        }
        if (min_length == n + 1) {
            printf("-1\n");
        } else {
            printf("%d\n", min_length);
        }
    }
    return 0;
}

